package com.example.mobilefinalproject

import androidx.core.os.bundleOf
import androidx.fragment.app.testing.launchFragmentInContainer
import androidx.test.ext.junit.runners.AndroidJUnit4
import androidx.test.filters.MediumTest
import androidx.test.espresso.Espresso.onView
import androidx.test.espresso.assertion.ViewAssertions.matches
import androidx.test.espresso.matcher.ViewMatchers.withId
import androidx.test.espresso.matcher.ViewMatchers.withText
import com.example.mobilefinalproject.models.MockDeliveryDataSource
import com.example.mobilefinalproject.ui.driver.DriverFinderFragment
import com.example.mobilefinalproject.ui.driver.DriverFinderMapClusterer
import org.junit.Assert.assertTrue
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
@MediumTest
class DriverFinderFragmentTest {

    @Test
    fun selectingDeliveryShowsDetailBottomSheet() {
        val delivery = MockDeliveryDataSource.deliveries.first()
        val scenario = launchFinderFragment()

        scenario.onFragment { fragment ->
            fragment.handleDeliverySelection(delivery)
        }

        onView(withId(R.id.tv_order_id))
            .check(matches(withText(fragmentString(R.string.order_id_format, delivery.id))))
        onView(withId(R.id.tv_customer_name))
            .check(matches(withText(delivery.customerName)))
        onView(withId(R.id.tv_pickup_address))
            .check(matches(withText(delivery.pickupAddress)))
        onView(withId(R.id.tv_dropoff_address))
            .check(matches(withText(delivery.dropoffAddress)))
    }

    @Test
    fun zoomIntoClusterIncreasesMapZoom() {
        val scenario = launchFinderFragment()
        val cluster = DriverFinderMapClusterer.cluster(
            DriverFinderMapClusterer.toMapPoints(MockDeliveryDataSource.deliveries),
            zoom = 9.0,
        ).first { it.points.size > 1 }

        scenario.onFragment { fragment ->
            val initialZoom = fragment.currentZoomLevel()

            fragment.zoomIntoCluster(cluster.centerLatitude, cluster.centerLongitude)

            assertTrue(fragment.currentZoomLevel() > initialZoom)
        }
    }

    private fun launchFinderFragment() = launchFragmentInContainer<DriverFinderFragment>(
        fragmentArgs = bundleOf(
            DriverFinderFragment.ARG_SKIP_LOCATION_PERMISSION_CHECK to true,
        ),
        themeResId = R.style.Theme_MobileFinalProject,
    )

    private fun fragmentString(resId: Int, vararg args: Any): String {
        return androidx.test.platform.app.InstrumentationRegistry
            .getInstrumentation()
            .targetContext
            .getString(resId, *args)
    }
}

package com.example.mobilefinalproject.ui.driver

import com.example.mobilefinalproject.models.Delivery

object DriverFinderMapClusterer {

    data class DeliveryMapPoint(
        val latitude: Double,
        val longitude: Double,
        val delivery: Delivery,
        val markerType: MarkerType,
        val title: String,
        val snippet: String,
    )

    data class Cluster(
        val points: List<DeliveryMapPoint>,
        val centerLatitude: Double,
        val centerLongitude: Double,
    ) {
        val isSinglePoint: Boolean = points.size == 1
    }

    enum class MarkerType {
        PICKUP,
        DROPOFF,
    }

    fun toMapPoints(deliveries: List<Delivery>): List<DeliveryMapPoint> = buildList {
        deliveries.forEach { delivery ->
            if (delivery.pickupLat != 0.0 || delivery.pickupLng != 0.0) {
                add(
                    DeliveryMapPoint(
                        latitude = delivery.pickupLat,
                        longitude = delivery.pickupLng,
                        delivery = delivery,
                        markerType = MarkerType.PICKUP,
                        title = "Pickup - ${delivery.customerName}",
                        snippet = delivery.pickupAddress,
                    )
                )
            }

            if (delivery.dropoffLat != 0.0 || delivery.dropoffLng != 0.0) {
                add(
                    DeliveryMapPoint(
                        latitude = delivery.dropoffLat,
                        longitude = delivery.dropoffLng,
                        delivery = delivery,
                        markerType = MarkerType.DROPOFF,
                        title = "Drop-off - ${delivery.customerName}",
                        snippet = delivery.dropoffAddress,
                    )
                )
            }
        }
    }

    fun cluster(points: List<DeliveryMapPoint>, zoom: Double): List<Cluster> {
        if (points.isEmpty()) {
            return emptyList()
        }

        val cellSizeDegrees = cellSizeDegrees(zoom)
        return points
            .groupBy { point ->
                val latBucket = (point.latitude / cellSizeDegrees).toInt()
                val lonBucket = (point.longitude / cellSizeDegrees).toInt()
                "$latBucket:$lonBucket"
            }
            .values
            .map { clusteredPoints ->
                Cluster(
                    points = clusteredPoints,
                    centerLatitude = clusteredPoints.map { it.latitude }.average(),
                    centerLongitude = clusteredPoints.map { it.longitude }.average(),
                )
            }
    }

    fun cellSizeDegrees(zoom: Double): Double = when {
        zoom < 10.0 -> 0.05
        zoom < 12.0 -> 0.02
        zoom < 14.0 -> 0.01
        zoom < 16.0 -> 0.005
        else -> 0.002
    }

    fun nextClusterZoom(currentZoom: Double): Double = (currentZoom + 1.0).coerceAtMost(20.0)
}

